// Catch-all for unhandled errors
app.use((err, req, res, next) => {
  console.error(err.stack); // Log internally
  res.status(err.status || 500).json({
    error: 'An unexpected error occurred.' // Never expose err.message to clients
  });
});

// Catch unhandled 404s
app.use((req, res) => {
  res.status(404).json({ error: 'Not found.' });
});
```

---

### 3. 🔴 No Rate Limiting (High Priority)
All endpoints are currently open to flooding/DoS. Use `express-rate-limit`:

```js
const rateLimit = require('express-rate-limit');
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100,                  // Max requests per window per IP
  standardHeaders: true,
  legacyHeaders: false,
});
app.use(limiter);
```

---

### 4. 🟡 No Input Validation for Query Parameters (Medium Priority)
Even for GET endpoints, query parameters (e.g., `?id=...`, `?page=...`) should be validated to prevent injection. Use a library like `zod` or `joi`:

```js
const { z } = require('zod');

// Example: if /users ever accepts query params
app.get('/users', (req, res, next) => {
  const schema = z.object({
    page: z.coerce.number().int().min(1).optional(),
    limit: z.coerce.number().int().min(1).max(100).optional(),
  });
  const result = schema.safeParse(req.query);
  if (!result.success) {
    return res.status(400).json({ error: 'Invalid query parameters.', details: result.error.flatten() });
  }
  // proceed with result.data
  res.json([...]);
});
```

---

### 5. 🟡 Hardcoded Port (Medium Priority)
The port `3000` is hardcoded. Use an environment variable to support different deployment environments:

```js
const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});
```

