### 2. 🚦 Rate Limiting
Protect endpoints from abuse and denial-of-service:
```js
const rateLimit = require('express-rate-limit');
const limiter = rateLimit({ windowMs: 15 * 60 * 1000, max: 100 });
app.use(limiter);
```

### 3. 📦 Body Parsing with Size Limits
If you add POST/PUT routes, always enforce a payload size limit:
```js
app.use(express.json({ limit: '10kb' }));
app.use(express.urlencoded({ extended: true, limit: '10kb' }));
```

### 4. ❌ Global Error Handling Middleware
Unhandled errors will currently crash or leak stack traces. Add a centralized error handler:
```js
app.use((err, req, res, next) => {
  console.error(err.stack); // Log internally, don't expose to client
  res.status(err.status || 500).json({ error: 'Internal Server Error' });
});
```

### 5. 🔍 404 Handler for Unknown Routes
Currently unknown routes get no response. Add a catch-all:
```js
app.use((req, res) => {
  res.status(404).json({ error: 'Not Found' });
});
```

### 6. 📡 Input Validation (for future routes)
When routes accept user input (query params, body), validate and sanitize with a library like `joi` or `express-validator`:
```js
const { query, validationResult } = require('express-validator');

app.get('/users', [
  query('id').optional().isInt({ min: 1 }).toInt(),
], (req, res) => {
  const errors = validationResult(req);
  if (!errors.isEmpty()) return res.status(400).json({ errors: errors.array() });
  // ... handler logic
});
```

### 7. 🕵️ Remove/Obscure `X-Powered-By` Header
Express advertises itself by default. `helmet` handles this, but you can also do it manually:
```js
app.disable('x-powered-by');
```

### 8. 📋 Structured Logging
Replace `console.log` with a structured logger like `pino` or `winston` so logs don't accidentally expose sensitive data:
```js
const pino = require('pino');
const logger = pino();
// app.listen(3000, () => logger.info('Server running on port 3000'));
```

### 9. ✅ Graceful Shutdown
Handle `SIGTERM`/`SIGINT` so the server closes cleanly (important in containers):
```js
const server = app.listen(3000, () => console.log('Server running on port 3000'));

process.on('SIGTERM', () => server.close(() => process.exit(0)));
process.on('SIGINT',  () => server.close(() => process.exit(0)));
```

### 10. 🔒 CORS Configuration
If this API is consumed by a browser, configure CORS explicitly rather than leaving it open:
```js
const cors = require('cors');
app.use(cors({ origin: ['https://yourdomain.com'], methods: ['GET', 'POST'] }));
```

